	_pMultiList->SetColumnTextWidth(3, 8);
	_pMultiList->SetColumnEditable(3, TRUE);
	_pMultiList->SetColumnItems(0, strFirstColumn, 7);
	_pMultiList->SetRowEditable(6,  FALSE);
