void MRFCircumVentCmdDlg::ClearOtherSelections(CATString istrData)
{
	if (istrData == "BackProfile")
	{
		_pTyreAssySelector->ClearSelect();
		_pDefaultRevolvesSelector->ClearSelect();
		_pMergedRevolvesSelector->ClearSelect();
		_pLateralRevolvesSelector->ClearSelect();
	}
	else if (istrData == "TyreAssy")
	{
		_pBackProfileSelector->ClearSelect();
		_pDefaultRevolvesSelector->ClearSelect();
		_pMergedRevolvesSelector->ClearSelect();
		_pLateralRevolvesSelector->ClearSelect();
	}
	else if (istrData == "DefaultRevolves")
	{
		_pBackProfileSelector->ClearSelect();
		_pTyreAssySelector->ClearSelect();
		_pMergedRevolvesSelector->ClearSelect();
		_pLateralRevolvesSelector->ClearSelect();
	}
	else if (istrData == "MergedRevolves")
	{
		_pBackProfileSelector->ClearSelect();
		_pTyreAssySelector->ClearSelect();
		_pDefaultRevolvesSelector->ClearSelect();
		_pLateralRevolvesSelector->ClearSelect();
	}
	else if (istrData == "LateralRevolves")
	{
		_pBackProfileSelector->ClearSelect();
		_pTyreAssySelector->ClearSelect();
		_pDefaultRevolvesSelector->ClearSelect();
		_pMergedRevolvesSelector->ClearSelect();
	}
}

CATDlgContextualMenu* MRFCircumVentCmdDlg::GetContextualMenu(const char* contextMenuType)
{
	CATString contexType = contextMenuType;
	CATDlgContextualMenu* contxMenu = NULL;
	if (contexType == "BackProfile")
	{
		return _pContexMenuSelListBackProfSurf;
	}
	else if (contexType == "TyreAssy")
	{
		return _pContexMenuSelListTyreSurf;
	}
	else if (contexType == "DefaultRevolves")
	{
		return _pContexMenuSelListDefVentSet;
	}
	else if (contexType == "MergedRevolves")
	{
		return _pContexMenuSelListMergVentSet;
	}
	else if (contexType == "LateralRevolves")
	{
		return _pContexMenuSelListLateralVentSet;
	}

	return contxMenu;
}

//-----------Function to set focus on selector List when selector list is clicked by user STARTS--------------//
void MRFCircumVentCmdDlg::SetFocusOnSelectorList(CATDlgSelectorList * ipSelectorList)
{
	if (!!ipSelectorList)
	{
		static int arrRow[1] = { 0 };
		ipSelectorList->SetSelect(arrRow, 1, 0);
		SetFocusOn(ipSelectorList);

	}
}
//

//------------Function to set name to be displayed at VentGeom Set Selector List STARTS------------//
void MRFCircumVentCmdDlg::SetSelectorListVentGeomSet(const CATUnicodeString objName, CATDlgSelectorList* selecList)
{
	selecList->ClearLine();
	selecList->SetLine(objName);
	SetFocusOnSelectorList(selecList);
}
